230	int yr_arena_create(
231	    int number_of_buffers,
232	    size_t initial_buffer_size,
233	    YR_ARENA** arena)
234	{
235	  YR_ARENA* new_arena = (YR_ARENA*) yr_calloc(1, sizeof(YR_ARENA));
236	
237	  if (new_arena == NULL)
238	    return ERROR_INSUFFICIENT_MEMORY;
239	
240	  new_arena->xrefs = 1;
241	  new_arena->num_buffers = number_of_buffers;
242	  new_arena->initial_buffer_size = initial_buffer_size;
243	
244	  *arena = new_arena;
