255	//
256	// yr_arena_release
257	//
258	// Releases the arena. If the number of cross-references to this arena drops
259	// to zero the arena is destroyed and all its resources are freed.
260	//
261	// Args:
262	//    [in] YR_ARENA* arena    - Pointer to the arena.
263	//
264	
265	int yr_arena_release(
266	    YR_ARENA* arena)
267	{
268	  arena->xrefs--;
269	
270	  if (arena->xrefs > 0)
271	    return ERROR_SUCCESS;
272	
273	  for (int i = 0; i < arena->num_buffers; i++)
274	  {
275	    if (arena->buffers[i].data != NULL)
276	      yr_free(arena->buffers[i].data);
277	  }
278	
279	  YR_RELOC* reloc = arena->reloc_list_head;
280	
281	  while (reloc != NULL)
282	  {
283	    YR_RELOC* next = reloc->next;
284	    yr_free(reloc);
285	    reloc = next;
286	  }
287	
288	  yr_free(arena);
289	
290	  return ERROR_SUCCESS;
291	}
